record.field:
for wizard in self:
    location = wizard.x_quant_id.location_id
    lot = wizard.x_quant_id.lot_id
    product = wizard.x_quant_id.product_id
    move_line_id = wizard.x_move_id.move_line_ids.filtered(
        lambda ml: ml.location_id == location and ml.lot_id == lot and ml.product_id == product
    )[:1]
    if move_line_id:
        wizard['x_quantity'] = move_line_id.quantity
    else:
        wizard['x_quantity'] = 0.0

for wizard in self:
    attribute = wizard.x_product_id.product_tmpl_id.attribute_line_ids.filtered(
        lambda l: l.attribute_id.x_is_convert_attribute
    )[:1].attribute_id
    wizard['x_convert_attribute_id'] = attribute

for wizard in self:
    allowed = wizard.env['product.product']

    if not wizard.x_product_id:
        wizard['x_allowed_product_ids'] = [(6, 0, [])]
        continue

    source = wizard.x_product_id

    for product in wizard.env['product.product'].search([]):

        # 1. skip same product
        if product.id == source.id:
            continue

        # 2. attribute rules
        src_ptavs = source.product_template_attribute_value_ids
        tgt_ptavs = product.product_template_attribute_value_ids

        src_convert = src_ptavs.filtered(lambda p: p.attribute_id.x_is_convert_attribute)
        src_fixed = src_ptavs - src_convert

        if not all(val.product_attribute_value_id in
                tgt_ptavs.mapped('product_attribute_value_id')
                for val in src_fixed):
            continue

        if any(val.product_attribute_value_id in
            tgt_ptavs.mapped('product_attribute_value_id')
            for val in src_convert):
            continue

        # 3. tracking rules
        if wizard.x_keep_lot_sn or wizard.x_new_lot_sn_id:
            if product.tracking != source.tracking:
                continue
        else:
            if product.tracking != 'quantity' and product.is_storable:
                continue

        allowed |= product

    wizard['x_allowed_product_ids'] = [(6, 0, allowed.ids)]
